class LinkParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.links = set()
    def handle_starttag(self, tag, attrs):
        d = dict(attrs)
        if 'href' in d:
            self.links.add(d['href'])
        if 'src' in d:
            self.links.add(d['src'])
        # forms
        if tag == 'form' and 'action' in d:
            self.links.add(d['action'])

