import hashlib, itertools
ph='0cda9742a5f7afc070294c47d5058dc1ee5d5e88141d2829cbbe0b7d0a9924ea'
password='test'
salts=['','salt','secret','pepper','key','flask','werkzeug','debian','apache','router','Router','xyz','XYZ','RouterXYZ','routerxyz','r0uter','admin','password','123','2025','2026']
patterns=[
    lambda s,p: s+p,
    lambda s,p: p+s,
    lambda s,p: s+p+s,
    lambda s,p: p[::-1]+s,
    lambda s,p: s+p[::-1],
    lambda s,p: s+':'+p,
    lambda s,p: p+':'+s,
]
hashes=[('sha256',lambda x: hashlib.sha256(x).hexdigest()),('sha1',lambda x: hashlib.sha1(x).hexdigest()),('md5',lambda x: hashlib.md5(x).hexdigest())]
found=[]
for name,hf in hashes:
    for s1 in salts:
        for pat in patterns:
            cand = pat(s1,password).encode()
            if hf(cand)==ph:
                found.append((name,s1,'pattern',pat.__name__))
    # also combo of two salts
    for s1 in salts:
        for s2 in salts:
            for pat in patterns:
                cand = pat(s1,password)+s2
                cand=cand.encode()
                if hf(cand)==ph:
                    found.append((name,s1,s2,'pattern2',pat.__name__))

print('found',found[:5], 'count', len(found))
